import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { auth, db } from '../firebase';
import { collection, getDocs, orderBy, query } from 'firebase/firestore';
import { signOut } from 'firebase/auth';

function Home() {
  const [events, setEvents] = useState([]);
  const navigate = useNavigate();
  const user = auth.currentUser;

  useEffect(() => {
    const fetchEvents = async () => {
      const q = query(collection(db, 'events'), orderBy('date', 'asc'));
      const snapshot = await getDocs(q);
      const list = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setEvents(list);
    };
    fetchEvents();
  }, []);

  const handleLogout = async () => {
    await signOut(auth);
  };

  return (
    <div style={{ backgroundColor: '#1a1a2e', minHeight: '100vh', color: 'white', padding: '20px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h1>⚔️ PartyRagnarok</h1>
        <div>
          <button onClick={() => navigate('/profile')} style={btnStyle('#4285f4')}>👤 Profilo</button>
          <button onClick={() => navigate('/create-event')} style={btnStyle('#2ecc71')}>➕ Crea Evento</button>
          <button onClick={handleLogout} style={btnStyle('#e74c3c')}>🚪 Esci</button>
        </div>
      </div>

      <h2 style={{ marginBottom: '20px' }}>📅 Eventi in programma</h2>

      {events.length === 0 && <p style={{ color: '#aaa' }}>Nessun evento disponibile. Creane uno!</p>}

      {events.map(event => {
        const totalSlots = event.slots ? Object.values(event.slots).reduce((a, b) => a + b, 0) : 0;
        const totalBooked = event.participants ? event.participants.length : 0;
        const isFull = totalBooked >= totalSlots;

        return (
          <div key={event.id} onClick={() => navigate(`/event/${event.id}`)} style={{
            backgroundColor: '#16213e',
            borderRadius: '10px',
            padding: '20px',
            marginBottom: '15px',
            cursor: 'pointer',
            borderLeft: `5px solid ${isFull ? '#e74c3c' : '#2ecc71'}`
          }}>
            <h3>{event.name}</h3>
            <p>📅 {new Date(event.date).toLocaleString('it-IT')}</p>
            <p>👥 {totalBooked}/{totalSlots} partecipanti {isFull ? '🔴 Completo' : '🟢 Aperto'}</p>
          </div>
        );
      })}
    </div>
  );
}

const btnStyle = (color) => ({
  padding: '8px 15px',
  marginLeft: '10px',
  backgroundColor: color,
  color: 'white',
  border: 'none',
  borderRadius: '6px',
  cursor: 'pointer'
});

export default Home;
